import unreal, json
actors = unreal.EditorLevelLibrary.get_all_level_actors()
ps = None
demo = []
for a in actors:
    lbl = a.get_actor_label()
    cls = a.get_class().get_name()
    loc = a.get_actor_location()
    if 'PlayerStart' in cls or 'PlayerStart' in lbl:
        ps = {'name': lbl, 'location': [round(loc.x), round(loc.y), round(loc.z)]}
    if lbl.startswith('Demo_'):
        demo.append({'name': lbl, 'location': [round(loc.x), round(loc.y), round(loc.z)]})
print(json.dumps({'player_start': ps, 'demo_actors': demo, 'total_actors': len(actors)}))

import unreal, json
try:
    actors = unreal.EditorLevelLibrary.get_all_level_actors()
    demo = [a for a in actors if a.get_actor_label().startswith('Demo_')]
    info = []
    for a in demo:
        loc = a.get_actor_location()
        _, ext = a.get_actor_bounds(True)
        info.append({
            'label': a.get_actor_label(),
            'x': loc.x, 'y': loc.y, 'z': loc.z,
            'ex': max(abs(ext.x), 80), 'ey': max(abs(ext.y), 80)
        })
    pairs = []
    for i in range(len(info)):
        for j in range(i+1, len(info)):
            a, b = info[i], info[j]
            dx = abs(a['x'] - b['x'])
            dy = abs(a['y'] - b['y'])
            dz = abs(a['z'] - b['z'])
            # Collision if XY overlap AND Z difference < 200 (not stacked)
            if dx < a['ex'] + b['ex'] and dy < a['ey'] + b['ey'] and dz < 200:
                pairs.append({'a': a['label'], 'b': b['label']})
    print(json.dumps({'collision_count': len(pairs), 'pairs': pairs, 'demo_count': len(demo)}))
except Exception as e:
    print(json.dumps({'collision_count': -1, 'error': str(e)}))

